import {ScrollLock} from '../../utils/scroll-lock.js';
import {FocusLock} from '../../utils/focus-lock.js';

export class MainNav {
  constructor() {
    this._mainNav = document.querySelector('[data-main-nav]');
    this._toggles = document.querySelectorAll('[data-toggle-nav]');
    this._scrollLock = new ScrollLock();
    this._focusLock = new FocusLock();
    this._isMenuOpen = false;

    this._onToggleClick = this._onToggleClick.bind(this);
    this._onDocumentKeydown = this._onDocumentKeydown.bind(this);
    this._onDocumentClick = this._onDocumentClick.bind(this);
  }

  init() {
    if (!this._toggles.length || !this._mainNav) {
      console.warn('MainNav or Toggles not found');
      return;
    }

    this._toggles.forEach((toggle) => {
      toggle.addEventListener('click', this._onToggleClick);
    });
  }

  _openMenu() {
    this._isMenuOpen = true;
    this._mainNav.classList.add('is-open');
    
    // Добавляем класс is-active всем кнопкам
    this._toggles.forEach((toggle) => {
      toggle.classList.add('is-active');
    });
    
    this._scrollLock.disableScrolling();
    document.addEventListener('keydown', this._onDocumentKeydown);
    document.addEventListener('click', this._onDocumentClick);
    this._focusLock.lock('[data-main-nav]');
  }

  _closeMenu() {
    this._isMenuOpen = false;
    this._mainNav.classList.remove('is-open');
    
    this._toggles.forEach((toggle) => {
      toggle.classList.remove('is-active');
    });
    
    this._scrollLock.enableScrolling();
    document.removeEventListener('keydown', this._onDocumentKeydown);
    document.removeEventListener('click', this._onDocumentClick);
    this._focusLock.unlock('[data-main-nav]');
  }

  _onToggleClick() {
    if (this._isMenuOpen) {
      this._closeMenu();
    } else {
      this._openMenu();
    }
  }

  _onDocumentKeydown(evt) {
    if (evt.key === 'Escape') {
      this._closeMenu();
    }
  }

  _onDocumentClick(evt) {
    if (evt.target.hasAttribute('data-close-menu')) {
      this._closeMenu();
    }
  }
}